@spec vm_editing_spec  src=tests/specs/vm_editing_spec.lua  loc=537  sha=6fb5e8f  cases=15
@exercises trackerView (h.vm), editCursor (h.ec), commandManager (h.cmgr), midiManager (h.fm), trackerManager (h.tm)
@surface   vm:setGridSize, ec:setPos, cmgr:invoke, fm:dump, tm:getChannel, vm:editEvent
@harness   mk{seed.notes, seed.ccs}

# Intent
  Exercises vm editing commands against seeded tm state.

# Cases
  @case 'delete on delay stop zeroes delay metadata'  [harness]  @ 14-38
  @case 'growNote past a same-pitch successor authors a tail past, tm clips realised'  [harness]  @ 47-67
  @case 'noteOff at the rendered tail row reopens authored endppq to util.OPEN'  [harness]  @ 75-92
  @case 'noteOff reopens a tail to util.OPEN under fractional ppqPerRow'  [harness]  @ 102-121
  @case 'placing a new note clears same-pitch coverage in other cols of the channel'  [harness]  @ 131-171
  @case 'placing a new note clamps its endppq to a same-pitch successor in another col'  [harness]  @ 179-215
  @case 'delete on pitch tied predecessor extends to next note'  [harness]  @ 223-256
  @case 'growNote past an open-tailed same-pitch predecessor does not throw'  [harness]  @ 265-289
  @case 'delete on vel inherits from a prior PA event'  [harness]  @ 295-318
  @case 'delete on pitch over a PA cell is a no-op'  [harness]  @ 324-347
  @case 'selection pitch delete leaves PAs alone'  [harness]  @ 355-383
  @case 'selection vel delete deletes PAs and resets note vels'  [harness]  @ 388-414
  @case 'edit existing PA value reads vel and persists via val'  [harness]  @ 422-447
  @case 'PA stamped under swing is reachable and deletable'  [harness]  @ 455-512
  @case 'delete on delay stop is a no-op when delay is already 0'  [harness]  @ 516-535

